import{_ as i,c as e,m as a,a as l,t as n,U as t,o as r}from"./chunks/framework.9QHaLlVJ.js";const y=JSON.parse('{"title":"RollingUpdate[滚动更新]","description":"","frontmatter":{"title":"RollingUpdate[滚动更新]"},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Deployment/升级策略/RollingUpdate.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Deployment/升级策略/RollingUpdate.md","lastUpdated":1705159462000}'),p={name:"doc/DevOps/Kubernetes/基础/Deployment/升级策略/RollingUpdate.md"},o={id:"frontmatter-title",tabindex:"-1"},d=a("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),h=t(`<ul><li><a href="https://kubernetes.io/zh-cn/docs/concepts/workloads/controllers/deployment/" target="_blank" rel="noreferrer">官方文档</a></li></ul><p>滚动升级，即逐步创建新Pod再删除旧Pod。</p><h2 id="过程" tabindex="-1">过程 <a class="header-anchor" href="#过程" aria-label="Permalink to &quot;过程&quot;">​</a></h2><ul><li>先启动新版本的pod</li><li>删除旧版本的pod</li><li>逐步增加新版本的pod数量</li><li>逐步减少旧版本的pod数量</li><li>直到所有pod都运行新版本</li></ul><h2 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h2><ul><li>更新过程会出现新旧版本同时存在</li><li>更新过程会有流量继续访问旧版本</li><li>服务不会中断，无需停机，风险小</li></ul><h2 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h2><details class="details custom-block"><summary>Details</summary><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  replicas</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  strategy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">RollingUpdate</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    rollingUpdate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      maxSurge</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      maxUnavailable</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></details><p>假设spec.replicas是2，如果maxSurge和maxUnavailable都为默认值25%，那实际升级过程中，maxSurge允许最多3个Pod存在（向上取整，2<em>1.25=2.5，取整为3），而maxUnavailable则不允许有Pod Unavailable（向上取整，2</em>0.75=1.5，取整为2），也就是说在升级过程中，一直会有2个Pod处于运行状态，每次新建一个Pod，等这个Pod创建成功后再删掉一个旧Pod，直至Pod全部为新Pod。</p><h2 id="思考" tabindex="-1">思考 <a class="header-anchor" href="#思考" aria-label="Permalink to &quot;思考&quot;">​</a></h2><p>使用时需要考虑究竟允不允许新旧版本同时存在，以及是否需要流量切换，自行评估可行性</p><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><ul><li>所有应用都使用控制器管理，并且必须多副本运行，尽量将副本分散到不同节点上。</li><li>为所有 Pod 添加 livenessProbe 和 readinessProbe。</li><li>容器进程在收到 SIGTERM 信号后优雅终止，比如持久化数据、清理网络连接等。</li><li>终止之前利用 preStop 稍等一会，等待各个组件异步操作完成。</li><li>必要时才设置 externalTrafficPolicy 为 Local，保留请求原始 IP。</li><li>使用 PodDiscruptionBudget 为应用设置中断预算，并总是使用 Eviction API（比如 kubectl drain）来清理 Pod，以确保遵循 PodDiscruptionBudget 的配置。</li></ul>`,13);function c(s,k,u,m,b,g){return r(),e("div",null,[a("h1",o,[l(n(s.$frontmatter.title)+" ",1),d]),h])}const P=i(p,[["render",c]]);export{y as __pageData,P as default};
